import AlchemystAI from '@alchemystai/sdk';

async function main() {
  const apiKey = process.env.ALCHEMYST_AI_API_KEY;
  const runId = process.env.ZEALT_RUN_ID || 'test_run_123';
  const sessionId = `team-standup-${runId}`;
  const userId = 'alice';

  console.log('Initializing client...');
  const client = new AlchemystAI({ apiKey });

  console.log('Testing client.v1.context.memory.add...');
  try {
    const addRes = await client.v1.context.memory.add({
      sessionId,
      contents: [
        {
          content: 'Alice says: We need to finish the deployment today.',
          user_id: userId, // Wait, let's see if user_id/userId is accepted inside content or top level
        }
      ]
    } as any);
    console.log('Add response:', JSON.stringify(addRes, null, 2));
  } catch (err: any) {
    console.error('Add failed:', err);
  }

  console.log('Testing client.v1.context.memory.search (via direct POST)...');
  try {
    const searchRes = await client.post('/api/v1/context/memory/search', {
      body: {
        userId,
        sessionId,
        query: 'deployment',
        similarity_threshold: 0.1,
        minimum_similarity_threshold: 0.1,
      }
    } as any);
    console.log('Search response:', JSON.stringify(searchRes, null, 2));
  } catch (err: any) {
    console.error('Search failed:', err);
  }
}

main();

